example.code:
class LoginPage extends BasePage {
  // role first — survives CSS refactors
  emailInput   = this.page.getByRole('textbox', { name: /email/i });
  passwordInput= this.page.getByRole('textbox', { name: /password/i });
  submitButton = this.page.getByRole('button',  { name: /log in/i });

  // test-id only when role is genuinely not applicable (e.g. non-semantic widget)
  rememberMeToggle = this.page.getByTestId('remember-me-toggle');
}

class LoginPage extends BasePage {
  emailInput   = this.page.locator('#email');                       // css
  passwordInput= this.page.locator('input[name="password"]');       // css
  submitButton = this.page.getByText('Log In');                     // text
  rememberMeToggle = this.page.locator('.login-form > div:nth-child(3) > input'); // brittle css
}
